#include <iostream>
#include <string>

template <typename T>
const T& getLarger(const T& val1, const T& val2) {
    return val1 > val2 ? val1 : val2;
}

int main() {
    int int_a = 42; int int_b = 100;
    std::cout << getLarger(int_a, int_b) << std::endl;

    double double_x = 99.9; double double_y = 99.89;
    std::cout << getLarger(double_x, double_y) << std::endl;

    int int_c = -5; int int_d = 0;
    std::cout << getLarger(int_c, int_d) << std::endl;

    double double_p = 1.234567; double double_q = 1.2345678;
    std::cout << getLarger(double_p, double_q) << std::endl;

    std::string str_s1 = "hello"; std::string str_s2 = "world";
    std::cout << getLarger(str_s1, str_s2) << std::endl;

    return 0;
}
